<!-- ES Module 自动 defer，支持 import -->

<!-- 4. 内联关键 JavaScript -->
<script>
// 关键渲染路径需要的 JavaScript 直接内联
// 减少网络请求次数
(function() {
  'use strict';
  // 关键逻辑，如首屏交互
})();
</script>
```

