  // ✅ 安全：React 自动转义
  return <div>{content}</div>;

  // ❌ 危险：跳过 React 的转义机制
  // return <div dangerouslySetInnerHTML={{ __html: content }} />;
}
```

```vue
<!-- Vue 示例 -->
<template>
  <!-- ✅ 安全：Vue 自动转义 -->
  <div>{{ userInput }}</div>

  <!-- ❌ 危险：v-html 会原样输出 HTML -->
  <div v-html="userInput"></div>
</template>
```

